def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        scale_factor = 1.0 + (item / (cap + 1))**2
        complexity = 0.0
        for m in range(1, 8):
            for n in range(1, 5):
                val = (np.sin(item * m / (cap + n)) + np.cos(cap * n / (item + 1))) * (m + n)
                if val > 0:
                    complexity += val / (m*n + 1)
                else:
                    complexity += val * (m + n)
            if cap % (m+2) == 0:
                scale_factor *= 1.03 + 0.005 * m
            else:
                scale_factor *= 0.97 - 0.004 * m
            if m == 4:
                inner_sum = 0.0
                for p in range(1, 10):
                    diff = cap - item * p * np.sqrt(p)
                    if diff > 0:
                        if diff % (p+1) == 0:
                            inner_sum += np.log1p(diff) / (p + 2)
                        else:
                            inner_sum -= (diff ** 0.7) / (p + 3)
                    else:
                        inner_sum -= abs(diff) ** 1.7 / (p + 4)
                complexity += inner_sum * 0.6
        ratio = item / cap
        modifier = 1.0
        if ratio < 0.3:
            modifier = np.exp(-ratio * 5)
        elif ratio > 0.7:
            modifier = np.log1p(ratio * 10)
        penalty = 0.0
        for q in range(1, 6):
            factor = ((cap + item * q) % (q+3)) * 0.1
            penalty += factor * np.tanh(ratio * q)
            if (cap * q + int(item)) % 4 == 0:
                penalty -= 0.05 * q
            if (item * q - cap) % 5 == 0:
                penalty += 0.03 * q
        base_score = complexity * scale_factor * modifier - penalty
        if base_score < 0:
            priorities[i] = -base_score * (1 + np.sqrt(cap)) * (1 + ratio)
        else:
            if cap < item * 2:
                priorities[i] = -base_score / (cap + 1) * np.exp(-ratio*3)
            else:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + 0.5 * ratio)
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.07
        if ratio > 1.0:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.8
    return priorities
